import{c as e,Q as i,j as a,m as o}from"./chunks/framework.hhGiamYR.js";const _=JSON.parse('{"title":"出使切萨雷","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/31-出使切萨雷.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/31-出使切萨雷.md"}'),r={name:"research/machiavelli/machiavelli/diplomatic/upper/31-出使切萨雷.md"};function c(t,p,l,m,s,d){return i(),a("div",null,[...p[0]||(p[0]=[o('<h1 id="出使切萨雷" tabindex="-1">出使切萨雷 <a class="header-anchor" href="#出使切萨雷" aria-label="Permalink to &quot;出使切萨雷&quot;">​</a></h1><p>出使切萨雷 ·博尔贾①</p><p>乌尔比诺，1502年6-7月</p><p>信件1</p><p>派遣弗朗切斯科 ·索德里尼主教和尼科洛 · 马基雅维利 出使瓦伦蒂诺公爵 1502年6月22日</p><p>伟大的诸位领主： 我们派遣在主基督里至为尊贵的沃尔泰拉主教弗朗切斯科 · 索德里尼 前去出使杰出的罗马涅公爵，在出使沿途所经之地，不再签发别的国书， 此行的目的是前去向上述公爵阁下通报情况，并请求他回复。</p><p>信件2</p><p>为索德里尼主教出使瓦伦蒂诺公爵出具的国书 1502年6月22日</p><p>杰出的领主、尊贵的公爵阁下： 按照阁下在信中对我们提出的要求，我们马上遵照执行，派遣受人尊 敬的沃尔泰拉主教弗朗切斯科 · 索德里尼大人出使阁下，他是佛罗伦萨公</p><p>①英译本未收入，依据贝尔泰利编校本译出，关于此次出使的背景参见《出使瓦伦蒂诺公爵》。 ——中 译者注</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>民，在我城品德最为高尚、最受人信任，并且我们赋予他极大的权力，我 们希望他在处理一切事务时拥有同我们一样的权威。大人同他会谈及处理 任何问题的时候，请给予最大的信任，他被委以全权行事。</p><p>信件3</p><p>索德里尼和马基雅维利致执政团</p><p>尊敬而杰出的诸位大人——我们致以诚挚的赞誉： 我们今天晚上到了蓬蒂切利，在这里遇到了彼得罗大人，他是杰出的 瓦伦蒂诺公爵派出的信使，我们从他那里听说那位公爵在乌尔比诺境内取 得了迅速而又轻松的胜利，尽管我们此前已经在西耶维桥从一位修士那里 听说了此事，让我们非常吃惊的是诸位大人竟然对此事一无所知，然而， 我们并没有尽力追赶那位修士。 这位彼得罗大人向我们表示，瓦伦蒂诺公爵确定乌尔比诺公爵已经逃 到了佛罗伦萨境内，希望通过此次彼得罗的出使，使诸位大人考虑到公爵 阁下长期以来对佛罗伦萨维持着深厚情谊和友好关系，能够做出让他欣慰 的事情。我们对他说，我们不相信那位领主现在佛罗伦萨境内且处于我们 的控制之下，而且我们深知我邦同瓦伦蒂诺公爵一直保持着友好关系。彼 得罗大人说他昨天晚上3点离开，他希望明天早上能够到达佛罗伦萨。诸 位大人在任何情况下都非常清楚如何应对这位彼得罗大人，处理好这个关 系，远甚于我们来做此事，因为我们还要赶路，我们将拭目以待。 他表示已经注意到了他的领主对诸位大人的态度，然而，他不满意你 们所做的冒犯他们的结果；诸位大人当然更好地知道如何来对待他。 明天早上，我们会一大早就上马启程，因为我们担心我们的马匹可能 会出问题，因为今天晚上，那些马太累了，道路依然漫长，而且路况很</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>糟；因为我们直接穿过乌尔比诺而行。 此次取胜的方式完全取决于这位领主的睿智英明，当时他在距离卡迈 里诺7英里的地方，粮草补给却在靠近卡利的地方，二者相距35英里；与 此同时，他突然发动了对卡迈里诺的围攻，并扫荡了那个地方。如此，诸 位大人必须注意这种战略谋划，并取得了如此迅速而又如此令人欢欣鼓舞 的胜利。</p><p>蓬蒂切利，1502年6月22日 弗朗切斯科 ·索德里尼主教</p><p>信件4</p><p>索德里尼和马基雅维利致执政团</p><p>尊敬的诸位大人： 今天早上，我们在梅尔卡泰洛通过快件收到了诸位大人23日的信，我 们立刻就将致公爵阁下的信转寄了出去，以使他看到诸位大人对他的友好 情谊以及你们的种种努力；我们在晚祷前到达此地。这位领主同此地的主 教大人①将我们安排到了主教府下榻，在大门口，我们遇到了他的秘书阿 加皮托大人和他的总管弗朗切斯科大人，鉴于我们都没有穿符合身份的礼 服，也就不用举行什么欢迎仪式；我们起先以为，他们得知我们的到来， 会让我们晚上就进去，然而，上述二人却不见了，因为各个方向都是大门 紧闭，主要考虑到不让兵士进去，我们费了好大劲才从旁边的一个门进 去；这样，我们才在房间里遇到了那两位大人。他们这才代表公爵欢迎我</p><p>①焦万 · 彼得罗 · 阿里瓦贝内( Giovan Pietro Arrivabene) 。——贝尔泰利编校本注</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>们，他们问我们什么时间会见公爵合适，由于我们是晚上2点到达的；我 们就去了公爵所住的宫殿，只有几个亲信和他在一起，这一次还是一样， 大门紧闭，把守森严。我们从2点以后的那段时间都和公爵阁下在一起， 我们首先按照诸位大人信中的嘱咐，向他通报了我们出使的任务，并对 他新近取得的胜利表示祝贺。我们看到，公爵对我们此次到来表示热烈欢 迎，对我们关怀备至，他说我们要将他的情谊以及两个邦国之间联盟的希 望带给佛罗伦萨。他对我们的祝贺表示感谢，并补充说，如果诸位大人知 道如何在时机成熟的时候做那些曾经对他承诺过的事情，他将更加感激不 尽。然后，他对自去年来到此地直至今日的过去一年中发生的事情表示遗 憾 ；这里不再重复，因为我们知道我们还要多次提到这些事情并回答，正 如我们现在做的一样；然而，似乎没有得出任何结论；他坚持正是那些缺 乏信任的人以及上述原因导致了在作战和招募兵员上的种种混乱，没有按 照承诺的那样提供服役合同和大炮。他说，那一次派遣使节前来仅仅是为 了表达友好愿望并企盼得到答复，尽管你们忽略了，没有经受住上一次的 考验，希望这一次派的人能够充分了解他的愿望，就是希望还是不希望同 你们结盟；他希望得到上帝和人们的宽恕，那些人试图以某种方式确认你 们拥有的态度；因为他认为无法确定你们的状态，无法同你们谈论国事， 除非很好地确认。一旦你们决定了此事，能够维持友好关系，你们就会得 到相应的好处；他把这句话说得非常详细。他表示非常了解去年的出使， 不仅是将逃跑的人归还佛罗伦萨当局，而且还给了你们一根权杖，只是一 根棍子而已。我对此的回答非常得体，就我们一方而言，在履行诺言上并 没有任何疏失，而是在采取行动时遭遇到了种种不利因素，我们告诉他， 如果对佛罗伦萨城邦较少考虑的话，那么他自己的利益也就无法得到充分 考虑。如果他希望得到诸位大人的友谊的话，你们不希望缺失公爵的友 谊，通过这种评价，诸位大人建立起同公爵及其邦国与教皇陛下之间的友 好关系；你们就能够借此尽快派遣使节，以便尽早满足他的希望，尤其是 了解他想说的那些话，以便诸位大人知道其心愿，公爵阁下也能够知晓你</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>们对他的评价。公爵阁下没有太多地绕圈子，直截了当地说：“我首先希 望知道，我要同什么人来达成我们的和解；然后，我还希望从你们那里得 到良好的安全保障；而如果这一切都谈妥了，我愿意在所有的问题上同你 们谈判；如果不行，我就不得不采取战争手段以求自保，无论你们采取什 么手段，我都不能让自己陷入危险之中。我非常了解你们城邦对我的态度 相当不友好，甚至阴谋刺杀我；而且，诸位大人总是试图让我承担不堪重 负的负担，教皇和法国国王亦是如此。”我们对他所说的后半部分内容予 以否认和驳斥，对其他内容则试图更好地澄清。他说： “我非常清楚地知 道，你们非常谨慎并希望让我了解你们的意图，然而，你们可以简明扼要 地直接告诉我。你们这届诸位大人不太喜欢我，我也无法信任他们，需要 把他们撤换，并让我确认能够观察到你们履行了对我的承诺；你们一定早 就听说过，我不愿意这样活着；除非你们希望与我友好相处，否则你们 将看到我会与你们敌对下去。”我们回答说，城邦的治理要超出人们的经 验，如果佛罗伦萨城邦的盟友都对其治理感到满意的话，他应该对其感到 满意；而一旦他发现自己的信心，他就不再认为在意大利有什么人有更好 的执政记录，甚至超出了他自己所经历的经验； 一旦公爵阁下决心按照他 所说的愿意对我城表示友好情谊，他就会发现友好的回报。他总是在谈话 时问到同样的事情，然而，同他无法达成任何形式的和解与信任；至于我 们谈到的事情，无法在这一点上说动他。我们抱怨说，这并非我们认为已 经得到澄清的事情，也并不是我城所希望的。他笑着问我们： “你们从自 己的想法出发相信些什么,我倒想听听你们如何向我说明?等等。”我们 说我们期待着公爵阁下的宽宏大量，并且我们认为通过阁下所表现出来的 友好情谊和信守承诺，我们能够期待双方愿意开始一种使双方获得更大利 益的关系，我们知道那座城(阿雷佐)目前在阁下掌控之下，尤其是在他 手下维泰洛佐大人手里。他对此回答说： “你们不要指望会去做那些对 你们有利的事情，因为不仅你们不配我这样做，而且我自己也不值得这样 做；的的确确，维泰洛佐是我的手下；然而我向你们起誓，有关阿雷佐谈</p><p>判的事情,我的确一无所知。我也还没有对你们所失去的东西感到不满, 甚至我对此还有些暗自庆幸,希望事情就这么发展下去。”我们要他给我 们一个理由,为什么要下令他的那些佣兵队长和手下进攻我们?他解释 说 : “维泰洛佐这么做是替其兄弟报仇,而我的军队没有掺和此事;甚至 我希望将你们的城池还给你们,我没有接收这些地方。但是,你们要早下 决心,因为我不能让我的军队在此地久留,这个地方多山,会给我们带来 很大的损害;而且,你们同我方尚未达成某种安排,要么成为朋友,要么 成为敌人。”这是最后的结论,我们认为那就是从所有这些话中能够得出 的,那些观点在很多地方比比皆是;公爵阁下在讲话中表示,由于我城管 理混乱导致的补给匮乏、军力虚弱和四分五裂,单单一个维泰洛佐就足以 击败你们;然而,你们这一方还要加上他的部队;他不想从你们那里得到 任何东西,由于他个人并不觊觎什么,他也不想僭越统治,而是要消灭那 些独夫民贼。我们就他提到的补给问题和应对措施回答了他,还有法国军 队以及法国国王对他心存芥蒂的事情。他总是说,如同意大利人一样,他 听到了一些关于法国的事情,他非常清楚自己没有上当受骗,而你们却仍 然蒙在鼓里。因此,我看到无法使他按照其他说法去做那些事情,也无法 使他改变这些想法;我们判断,此时此刻,巨大的胜利才能够让其改变他 对我们声称的那种做法等,我们不认为这对于你们信件的回复一无是处; 为的是留给诸位大人充裕的时间考虑这个问题,并看看我今天晚上是否会 得出更好的结论;我们说不希望将这个作为答复,而是我希望今天晚上再 考虑考虑,明天再同他谈,这样就能够给你们一个确切的消息。他说,他 已经对此深思熟虑过了,不打算做什么改变;然而,明天吃过饭之后,我 们还是会同他谈;而且我们会仔细考虑我们的利益和他的要求。就这样, 看到这种呼求最终会有什么结果,我们很难让我们自己满意,我们认为 这些事情相当重要,而且他们处理事情的方式,即使不是毫无小心谨慎而</p><p>马基雅维利全集 Opere complete di Niccolò Machiavelli</p><p>言，也绝非称得上老练到家。正如前面提到的这位领主①,人们首先听到 的是他去世的消息，而不是他生病的消息。因为没有时间查清楚，我们明 天先将这个消息发送给你们，一旦有进一步的情况，我们再报告。 我们听闻，在这位极为显赫并最杰出的领主的土地上，大约扣押了43 头骡子的佛罗伦萨货物，我们正千方百计地让他放行；他回答说： “货物 是安全的；如果你们想从我这里听到什么消息的话，你们会放心的，而且 不会失去任何东西；但是现在还不能放行。” 现在是25日的20点，这位领主到目前为止还没有传唤我们，然而，奥 尔西尼家族的朱利奥和保罗来拜访过我们，他们对佛罗伦萨城邦表达出了 他们的感受，也表现出了相当大的要为这位领主做某些有益的事情的决 心。我们回答说，对这位领主如此而行，对于我城也不要欠缺什么;他们 几乎复述了同样的事情，即要变更佛罗伦萨的政府，并使公爵放心。我们 对他们的回答如前所述，并进一步加强语气。然而，他们表示对于诸位大 人的事情了解了许多，这些事情已经把你们弄得焦头烂额了，我们无论如 何都要采用那些从他们那里得到的法律典章；或者真正臣服于法国国王之 下；从这一点出发，我们才能踏踏实实地谈论友谊，他们说： “如果没有 得到国王陛下的同意，你们相信我们会如此疯狂，发动如此规模的战事 吗?即使当时陛下没有同意，我们也会首先想方设法让他知道此事；而国 王陛下仍然会认为公爵阁下和奥尔西尼家族是他最为忠心耿耿的盟友，而 不会是你们；然而，他们取得的成功让他非常满意，增强的实力也最有效 地支持了佛罗伦萨执政团，并使得国王的利益得到了坚定的维护。”我们 非常激烈地反驳了这种说法，他们说，佩波大人②和他们的其他手下证实 了国王陛下和鲁昂教座大人的想法；此外还有，即使在一开始的时候，国 王和鲁昂教座大人不同意他们的想法，但在他们陈述了在德意志事务上的 损失以及咨询了3天后，国王对他们说： “你们尽管放手去做你们想做的</p><p>①乌尔比诺公爵圭多巴尔多 ·达 ·蒙特费尔特罗( Guidobaldo da Montefeltro)。——贝尔泰利编校本注 ②佩波 · 达 · 科尔瓦亚，潘多尔福 · 彼得鲁奇派驻法国的大使。 ——贝尔泰利编校本注</p><p>那件事，因为我不能拒绝许诺给佛罗伦萨人的军队；但我会小心谨慎地派 出这支军队，并给你们时间。”因为我在布莱的时候，①佩波大人在你们 那里，如果他表示国王陛下不会无故改变他的意愿而他们会尽早看到他的 人马和他本人的出现，他就会让你们遭受拒绝和打击。他们说： “我们其 中之一会上当受骗，但你们会远甚于此；然而，我们会继续向前，我们已 经占领了你们乡村地区的大部分，你们很快就会变得国土尽失，而我们兵 强马壮，大炮数量充足，而且法国军队随时会到，他们非常乐意地将你们 弃之不顾，而站在我们一边。”当我们表示公爵显然是友好而正义的，并 未出动他的骑兵来扫荡我们的国土；他们说： “你们看到的只是维泰洛佐 的军队所干的，而你们就要看到我们所做的事情，我们首先进入那些不再 是你们的领土，不再是你们的是因为你们守不住了。”他们表示，他们已 经制订了计划，马上就要实施；而他们愿意为此目的花费50达克特来准备 战马。总而言之，他们表示，这个行动计划就是公开针对诸位大人的，并 且准备出动骑兵；意在轻而易举取得胜利，无论是你们还是国王陛下都是 刚刚才听说此事；他们还说，他们知道骑兵的行进速度是每天40英里，不 消多时，就会兵临城下。 今天早上，科尔内里奥 ·伽兰蒂大人通过驿道系统到了这里，还有维 特利、佩波大人和潘多尔福的人，他们也没打算带什么东西来，因为这位 领主非常孤僻而且神秘；需要同他谈谈，或者亲自前来请求这位公爵同他 们联合，或者带上他们以及法国国王使者的信件同他沟通。我们没有放过 同他们交谈的机会，以了解那些领主的想法，他们在同国王接触的过程是 否涉及我城的事务，他们说： “因为还不清楚国王想要怎样对待公爵，你 们怎么能通过一封信就解除这个烦恼呢?”我们回答说，他已经做了那 事，还会再做一次，他们会很快看到，国王陛下无论对待忠心的下属还是 盟友都不是一个闹着玩的人。</p><p>①沃尔泰拉主教上一次在法国是1501年9月，与他同行的是卢卡 · 德利 · 阿尔比齐。 贝尔泰利编校本注</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>他们说，这位公爵阁下考虑到进入敌人在卡森蒂诺的战场，并在西耶 维桥大获全胜，并且已经下定决心进入你们的地盘；你们的那些队长和士 兵胆敢嗤笑的话，则阿雷佐的大部分将被夺取，过不了几天，你们就会 感到大不相同；科尔内里奥证实，维泰洛佐已经用“出自教皇阵营” ( ex Pontificiis castris) 的口气写信了。 这位领主在距离此地3英里的一个叫……①地方安营扎寨，他们称那个 地方有大约400重骑兵，300轻骑兵和3000步兵；此外，还有2000人马已 经在拉米罗大人②率领下从罗马涅赶来；在另外一个营盘位于卡迈里诺， 随时可以给予支援，他们说在那里有超过3000步兵，大约150长矛兵，另 外30多轻骑兵；他们整天都在异想天开地谈论着有更多的军队会来到，因 为他们一方兵多将广，能够优中选优，并且粮饷充裕；因此，他们估计从这 里到托斯卡纳，能够部署16000人，尽管他们还在谈论20000到25000人。 有关行政官③的情况，毫无疑问，他现在还不能得到这个位置，但很 快就会实现，而且不需要花费什么力气。 这位领主非常慷慨大度、杰出卓越，在军事方面相当有才华，事无巨 细，他都事必躬亲，认真对待，对于追求荣誉和夺取土地，他从来就不知 疲倦，不怕危险；如果他听到有什么办法可以夺取某个地方的话，他会马 不停蹄地首先赶往那里；尽全力激励他的士兵；他拥有全意大利第一流的 兵员和最好的人才；所有这些东西，再加上他的好运连连，使他战无不 胜，并为他带来赫赫威名。 我们现在的时间是3点，公爵已经派人传唤过我们，他重申了几乎同 样的事情；得出这样的结论，他不能也不愿意总是处于这种模棱两可的状 态中，而是希望得到我们的友谊；因此，他想要提到过的两件事情：要么</p><p>①此处原文有遗漏。 ——贝尔泰利编校本注 ②拉米罗 · 德 · 洛德瓜( Ramiro de Lorqua, 即雷米罗 · 德 · 奥尔科[Remirro de Orco]),瓦伦蒂诺公爵的 军官。——贝尔泰利编校本注 ③ 罗 马 行 政 官( del prefetto di Roma), 乔瓦尼 · 德拉 · 罗韦雷，塞尼加利亚的领主。 ——贝尔泰利编校 本注</p><p>断绝所谓的友谊，公开成为敌人；要么得到来自诸位大人的保证和正面 回复，他不愿意再等上4天；尽管我们再三请求，他仍然不同意延长。于 是，尽管我们已经计划好了在2天内处理完这里的一切返回，但还是看到 了更快的办法，我似乎没有办法做到这一点，是否可以让尼科洛尽快返回 佛罗伦萨，亲自向你们报告这里处理这些事务的进展情况，并不是因为他 能够告知这封信以外的什么内容，而是让他能够通过这个办法及时返回这 里，这件事如果可能的话只要花上一天多一点的时间：携带这封信的信使 马上出发，以使你们能够马上商讨相关事宜，在尼科洛到达的时候，就可 以告诉他你们的答复。还有一件事情需要提出，诸位大人要给我再派一名 助手，因为我对于如此沉重的职责已经感到不堪重负，无法独立支撑。 正如我所描述的，奥尔西尼家族的这些领主同这位领主足足吵了一 天，为的是说服他消灭诸位大人；但他没有同意，然而，他在这个间隙里 还是想先听听你们的想法。然而，诸位大人务必不要再拖延了，我们谦卑 地向诸位大人致意。</p><p>发自乌尔比诺，1502年6月26日，拂晓之前 仆弗朗切斯科 · 索德里尼 沃尔泰拉主教</p><p>信件5</p><p>索德里尼致执政团</p><p>诸位杰出的大人、我无比荣耀的主人： 向你们致敬! 昨天，我写了一封信，通过巴奇诺寄出，直到他离开， 一切都非常顺</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>利；今天早上，尼科洛出发返回佛罗伦萨了，以使诸位大人能够通过信件 和口头传达，让我们知道你们的想法，请诸位大人倾听尼科洛的意见，他 对这里的每件事都了如指掌，以便你们更好地解决问题。如果不是无法承 受快马加鞭地疾驰赶路所带来的旅途颠簸的话，我自己也非常愿意回去， 此外，我觉得在这种谈判的情形下离开也不太合适，等等。我非常诚恳地 请求诸位大人，就像以前做的那样，在每一件事情上，要么准许我卸任， 要么别让我处理某些类别的事情，为了使事情变得容易一些，请为我提供 这样的助手，不用考虑我能够如何为你们效力；否则就确定人选，在我不 堪重负的情况下，能够承担重任。 安东尼奥 ·达 · 韦纳弗罗大人昨天来到此地，是因为科尔内里奥 ·伽 兰蒂大人的事情，后者已经离开，大概是取道卡斯泰洛城回去了。有关他 所带来的消息或者商谈的内情不得而知，因为只有近卫扈从才得以进入宫 殿，寥寥数人才能同公爵阁下及其近臣会晤或面谈，那些未被召见的人不 得进入；能够合理地判断，他们尽一切可能推动公爵朝前走：所有留在此 地的这些人，都是狂热叫嚣反对佛罗伦萨之徒，百般恳求公爵加入他们的 事业。提到的安东尼奥大人和科尔内里奥大人今天都已经离开了。 今天，有人告诉我，步兵的一部分朝着圣阿诺洛和梅尔卡泰洛挺进， 而另一部分则前往罗马涅；但是，无法确认其中任何一支部队的情况。确 实存在这样的命令， 一旦接到指令，这支军队可以在1小时内出发，前往 任何要他们去的地方，而这全在这位领主自己的心中，如此善变多虑，每 次说起都佯装不知，而且在他做出行动之前从来不向任何人吐露实情。有 人猜测此次进军的方向应该是罗马涅，在其中的任何一处，只要能够进攻卡 斯特罗卡罗以及诸位大人的领地就行了，而博洛尼亚也受到严重的威胁。 笃信王陛下的一位使节同卡恰罗多莱一道已经来到公爵这里，我听说 那位使节已经完成了他的工作。公爵阁下告诉我，他非常谨慎小心地回 答，正如他惯常所做的那样；而他手下众多的队长和兵士有的口出狂言， 有的虚张声势谈论他的宏大场面和英勇传奇；我们等待着这个回复的内</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>容，以及随后所发生的情况，我希望明天将其附在信中。 有关卡迈里诺方面的情况，人们认为目前不应该管别的，已经造成了 损失，就任由此处遭受如此损失，还有此地的陷落并未损失太多的军队， 并未损失太多钱财，或者没有浪费太多时间。在那次战事中，发现格拉维 纳公爵①率领了大约100重骑兵以及另外100轻骑兵，1000步兵，还有许多 仆从兵②以及加斯科涅人。又有奥利韦尔罗托大人率领的从家乡费尔莫来 的200轻骑兵和1000步兵，而那些部队在指定的1个月内都是由其本人支付 军饷的。</p>',44)])])}const h=e(r,[["render",c]]);export{_ as __pageData,h as default};
